// Glob-discovers rule plugin files in lib/rules/defs and (re)generates the
// barrel lib/rules/defs/index.gen.ts. Runs on predev/prebuild so adding a rule
// file requires ZERO orchestration changes.
import fs from "node:fs";
import path from "node:path";

const defsDir = path.join(process.cwd(), "lib", "rules", "defs");
const files = fs
  .readdirSync(defsDir)
  .filter((f) => f.endsWith(".ts") && !f.startsWith("index."))
  .sort();

const ident = (f) => "r_" + f.replace(/\.ts$/, "").replace(/[^a-zA-Z0-9]/g, "_");

const lines = [
  "// AUTO-GENERATED by scripts/gen-rules-index.mjs — do not edit by hand.",
  "// Add a new rule by dropping a file in this directory; the barrel regenerates on dev/build.",
  'import type { Rule } from "@/lib/rules/types";',
  ...files.map((f) => `import ${ident(f)} from "./${f.replace(/\.ts$/, "")}";`),
  "",
  `export const ALL_RULES: Rule[] = [${files.map(ident).join(", ")}];`,
  "",
];

fs.writeFileSync(path.join(defsDir, "index.gen.ts"), lines.join("\n"));
console.log(`rules barrel: ${files.length} rules -> lib/rules/defs/index.gen.ts`);
